var sm = tree.current_scene._settings_menu
var f = tree.root.gui_get_focus_owner()
return f != null and sm.is_ancestor_of(f)

var sm = tree.current_scene._settings_menu
var f = tree.root.gui_get_focus_owner()
var sides = [SIDE_TOP, SIDE_BOTTOM, SIDE_LEFT, SIDE_RIGHT]
var escapes = 0
for s in sides:
	var n = f.find_valid_focus_neighbor(s)
	if n != null and not sm.is_ancestor_of(n):
		escapes += 1
return escapes

var sm = tree.current_scene._settings_menu
var cnt = 0
for c in sm._pad_confined_controls:
	if is_instance_valid(c) and c.focus_mode == Control.FOCUS_NONE:
		cnt += 1
return cnt > 0

var n = 0
for b in tree.current_scene.find_children("*", "Button", true, false):
	if b.is_visible_in_tree() and b.focus_mode == Control.FOCUS_ALL:
		n += 1
return n > 0
